const QUIZ_BANK_P1 = {
  1: [
    // Module 1 — Introduction to OSHA
    // MULTIPLE CHOICE (35)
    { type: 'mc', q: "What year was the Occupational Safety and Health Act signed into law?", options: ["1968", "1970", "1972", "1975"], a: 1, explain: "The OSH Act was signed by President Nixon on December 29, 1970.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which president signed the Occupational Safety and Health Act?", options: ["Lyndon Johnson", "Gerald Ford", "Richard Nixon", "Jimmy Carter"], a: 2, explain: "President Richard Nixon signed the OSH Act on December 29, 1970.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which CFR part covers OSHA construction standards?", options: ["29 CFR Part 1903", "29 CFR Part 1910", "29 CFR Part 1926", "29 CFR Part 1960"], a: 2, explain: "29 CFR Part 1926 covers safety and health regulations for construction.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which CFR part covers OSHA General Industry standards?", options: ["29 CFR Part 1903", "29 CFR Part 1910", "29 CFR Part 1926", "29 CFR Part 1960"], a: 1, explain: "29 CFR Part 1910 covers occupational safety and health standards for general industry.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which of the following is NOT one of the three core worker rights under OSHA?", options: ["Right to Know", "Right to Refuse unsafe work", "Right to Sue the employer", "Right to Participate in safety activities"], a: 2, explain: "The three OSHA worker rights are: Right to Know, Right to Participate, and Right to Refuse unsafe work. There is no OSHA 'Right to Sue.'", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "The General Duty Clause requires employers to:", options: ["Post OSHA citations in the break room", "Provide a workplace free from recognized hazards likely to cause death or serious harm", "Conduct annual safety inspections", "Hire a full-time safety officer"], a: 1, explain: "Section 5(a)(1) of the OSH Act — the General Duty Clause — requires employers to provide a workplace free from recognized hazards likely to cause death or serious physical harm.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "What is the maximum penalty for a Serious OSHA violation?", options: ["$7,000", "$10,000", "$16,131", "$161,323"], a: 2, explain: "A Serious violation carries a penalty of up to $16,131 per violation.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "What is the maximum penalty for a Willful or Repeated OSHA violation?", options: ["$16,131", "$70,000", "$161,323", "$250,000"], a: 2, explain: "Willful and Repeated violations each carry a maximum penalty of $161,323.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "A work-related fatality must be reported to OSHA within:", options: ["4 hours", "8 hours", "24 hours", "72 hours"], a: 1, explain: "Employers must report a work-related fatality to OSHA within 8 hours of learning of it.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "A work-related amputation must be reported to OSHA within:", options: ["8 hours", "12 hours", "24 hours", "72 hours"], a: 2, explain: "Work-related amputations, in-patient hospitalizations of three or more employees, and eye losses must be reported within 24 hours.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "How many states and territories have OSHA-approved State Plans?", options: ["12", "18", "22", "28"], a: 2, explain: "As of current standards, 22 states and territories operate their own OSHA-approved State Plans.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Under OSHA's multi-employer doctrine, which employer type creates the hazard?", options: ["Exposing employer", "Correcting employer", "Creating employer", "Controlling employer"], a: 2, explain: "The Creating employer is the one who causes the hazardous condition.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Under the whistleblower protection provisions, a worker must file a complaint within how many days of the discriminatory action?", options: ["15 days", "30 days", "60 days", "90 days"], a: 1, explain: "Section 11(c) gives workers 30 days to file a whistleblower complaint with OSHA after discriminatory action.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "An employer wishing to contest an OSHA citation must do so within:", options: ["10 working days", "15 working days", "30 calendar days", "60 calendar days"], a: 1, explain: "Employers must contest citations within 15 working days of receipt.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "During an OSHA inspection, the correct order of events is:", options: ["Walkaround → Opening conference → Closing conference", "Opening conference → Closing conference → Walkaround", "Opening conference → Walkaround → Closing conference", "Closing conference → Walkaround → Opening conference"], a: 2, explain: "OSHA inspections follow the order: Opening conference, then the Walkaround, then the Closing conference.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which type of OSHA violation applies when an employer knew or should have known about a hazard that is not likely to cause death or serious harm?", options: ["Serious", "Willful", "Other-Than-Serious", "Repeated"], a: 2, explain: "An Other-Than-Serious violation exists when the hazard does not have direct relationship to death or serious physical harm.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which type of OSHA citation is issued when an employer was previously cited for the same standard within the last five years?", options: ["Willful", "Serious", "Repeated", "Failure-to-Abate"], a: 2, explain: "A Repeated violation is issued when an employer has been cited for the same standard within the preceding five years.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "A Failure-to-Abate notice is issued when:", options: ["An employer files a contest", "An employer ignores a citation", "The hazard cited was not corrected by the abatement date", "A second inspection finds new hazards"], a: 2, explain: "Failure-to-Abate means the employer did not correct the previously cited hazard by the required abatement date.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "The OSHA 300A Summary must be posted:", options: ["January 1 – March 31", "February 1 – April 30", "March 1 – May 31", "Year-round"], a: 1, explain: "The OSHA 300A Annual Summary must be posted from February 1 through April 30 each year.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "What is the purpose of the OSHA 301 Incident Report form?", options: ["To summarize annual injury totals", "To document individual incident details within 7 days", "To notify OSHA of a fatality", "To record near-misses"], a: 1, explain: "The OSHA 301 is an individual incident report that must be completed within 7 days of a recordable event.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which variance type allows an employer to use a different method temporarily while developing a permanent solution?", options: ["Permanent variance", "Experimental variance", "Interim variance", "Temporary variance"], a: 3, explain: "A Temporary variance gives an employer time to comply with a new standard while developing compliant procedures.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which OSHA recordkeeping form is the 'Log of Work-Related Injuries and Illnesses'?", options: ["OSHA 300", "OSHA 300A", "OSHA 301", "OSHA 302"], a: 0, explain: "The OSHA 300 is the Log of Work-Related Injuries and Illnesses.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Who may accompany an OSHA compliance officer during the walkaround inspection?", options: ["Only the employer representative", "Only an OSHA supervisor", "Both an employer representative and an employee representative", "The site owner only"], a: 2, explain: "Both an employer representative and an employee representative have the right to accompany the OSHA officer during the walkaround.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "A worker has the right to refuse work they believe is dangerous. Under OSHA, this is known as:", options: ["The General Duty Clause", "Section 11(c) protection", "The Right to Refuse unsafe work", "Imminent danger authority"], a: 2, explain: "The Right to Refuse unsafe work is one of the three core worker rights under OSHA.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "OSHA's whistleblower protection under the OSH Act is found in:", options: ["Section 5(a)(1)", "Section 11(c)", "29 CFR 1926.21", "29 CFR 1910.1200"], a: 1, explain: "Section 11(c) of the OSH Act prohibits employer retaliation against workers who exercise their OSHA rights.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Under the multi-employer worksite doctrine, the employer who is responsible for correcting a hazard it did not create is the:", options: ["Creating employer", "Exposing employer", "Correcting employer", "Controlling employer"], a: 2, explain: "The Correcting employer has the responsibility to correct hazardous conditions, even those they did not create.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which of the following OSHA inspection priority types is highest?", options: ["Programmed inspections", "Referrals", "Complaints", "Imminent danger"], a: 3, explain: "Imminent danger situations receive the highest priority for OSHA inspections.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "A State Plan must be at least _____ as effective as the federal OSHA program.", options: ["Equally", "Twice", "Three times", "Half"], a: 0, explain: "State Plans must be 'at least as effective' as the federal OSHA program.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Under OSHA, employers must keep OSHA 300 Logs for at least:", options: ["1 year", "3 years", "5 years", "10 years"], a: 2, explain: "OSHA requires employers to retain the 300 Log, 300A Summary, and 301 Incident Reports for five years.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Which employer in the multi-employer doctrine has overall supervisory authority over the worksite?", options: ["Creating employer", "Exposing employer", "Correcting employer", "Controlling employer"], a: 3, explain: "The Controlling employer has general supervisory authority over the worksite and is responsible for safety conditions overall.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "An OSHA citation must be posted:", options: ["In the company's main office", "At or near the location of the alleged violation", "On the OSHA bulletin board at headquarters", "Only provided to the employee representative"], a: 1, explain: "Citations must be posted at or near the location of the alleged violation until it is corrected or for three working days, whichever is longer.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "An employer who intentionally and knowingly violates OSHA standards receives which citation type?", options: ["Serious", "Other-Than-Serious", "Repeated", "Willful"], a: 3, explain: "A Willful violation is one where the employer intentionally and knowingly violates a standard or is plainly indifferent to employee safety.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "Workers have the right to receive information about hazardous substances they work with. This is known as:", options: ["Right to Participate", "Right to Refuse", "Right to Know", "Right to Inspect"], a: 2, explain: "The Right to Know includes access to hazard information, Safety Data Sheets, and exposure records.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "How long must an OSHA citation be posted at the violation site?", options: ["Until abatement or 3 working days, whichever is longer", "7 calendar days", "Until the employer contests it", "30 calendar days"], a: 0, explain: "Citations must remain posted until the violation is corrected or for three working days, whichever is longer.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'mc', q: "The OSH Act covers which of the following workers?", options: ["Federal government employees only", "Private sector employees and some public sector employees", "Union workers only", "Only workers in states without a State Plan"], a: 1, explain: "The OSH Act covers most private sector employers and workers, as well as some public sector workers in states with approved State Plans.", moduleRef: 1, moduleName: "Introduction to OSHA" },

    // FILL IN THE BLANK (8)
    { type: 'fib', q: "The OSH Act was signed on December 29, ___.", answer: "1970", accept: [], explain: "The Occupational Safety and Health Act was signed by President Nixon on December 29, 1970.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "Construction safety standards are found in 29 CFR Part ___.", answer: "1926", accept: ["part 1926"], explain: "29 CFR Part 1926 contains OSHA's safety and health regulations for the construction industry.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "An employer must report a work-related fatality to OSHA within ___ hours.", answer: "8", accept: ["eight"], explain: "Fatalities must be reported to OSHA within 8 hours of the employer learning of the death.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "An employer must contest an OSHA citation within ___ working days.", answer: "15", accept: ["fifteen"], explain: "Employers have 15 working days from receipt of a citation to formally contest it.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "A whistleblower complaint under Section 11(c) must be filed within ___ days of the discriminatory act.", answer: "30", accept: ["thirty"], explain: "Workers have 30 days to file a Section 11(c) whistleblower complaint with OSHA.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "The OSHA 300A Annual Summary must be posted from February 1 through ___ 30.", answer: "April", accept: ["april 30"], explain: "The 300A must be posted from February 1 through April 30 of the year following the recorded injuries.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "The maximum penalty for a Willful OSHA violation is $___, ___ per violation.", answer: "161,323", accept: ["$161,323", "161323"], explain: "Willful and Repeated violations can each result in a maximum penalty of $161,323.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'fib', q: "Under the OSH Act, the ___ Duty Clause requires employers to provide a workplace free from recognized hazards.", answer: "General", accept: ["general duty"], explain: "Section 5(a)(1), the General Duty Clause, is the broad employer obligation to maintain a hazard-free workplace.", moduleRef: 1, moduleName: "Introduction to OSHA" },

    // SELECT ALL THAT APPLY (7)
    { type: 'sa', q: "Which of the following are types of OSHA citations? (Select all that apply)", options: ["Other-Than-Serious", "Negligent", "Willful", "Repeated"], answers: [0, 2, 3], explain: "Other-Than-Serious, Willful, and Repeated are all valid OSHA citation types. 'Negligent' is not an OSHA citation category.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following are core worker rights under OSHA? (Select all that apply)", options: ["Right to Know", "Right to a raise", "Right to Participate", "Right to Refuse unsafe work"], answers: [0, 2, 3], explain: "OSHA guarantees workers the Right to Know, Right to Participate in safety activities, and Right to Refuse unsafe work.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following are valid OSHA variance types? (Select all that apply)", options: ["Temporary variance", "Emergency variance", "Permanent variance", "Experimental variance"], answers: [0, 2, 3], explain: "OSHA recognizes Temporary, Permanent, and Experimental variances. 'Emergency variance' is not an official OSHA variance type.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following are employer types under OSHA's multi-employer worksite doctrine? (Select all that apply)", options: ["Creating employer", "Exposing employer", "Licensing employer", "Controlling employer"], answers: [0, 1, 3], explain: "The multi-employer doctrine identifies Creating, Exposing, Correcting, and Controlling employers. 'Licensing employer' is not a recognized category.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following OSHA recordkeeping forms are required for most employers with 11 or more employees? (Select all that apply)", options: ["OSHA 300 Log", "OSHA 300A Summary", "OSHA 400 Hazard Report", "OSHA 301 Incident Report"], answers: [0, 1, 3], explain: "Employers with 11 or more employees must maintain the OSHA 300 Log, 300A Summary, and 301 Incident Report. There is no OSHA 400 form.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following events require reporting to OSHA? (Select all that apply)", options: ["Work-related fatality", "Work-related amputation", "Near-miss with no injury", "In-patient hospitalization of 3 or more employees"], answers: [0, 1, 3], explain: "Fatalities (within 8 hours), amputations (within 24 hours), and in-patient hospitalizations of 3+ employees (within 24 hours) must be reported to OSHA. Near-misses do not require OSHA notification.", moduleRef: 1, moduleName: "Introduction to OSHA" },
    { type: 'sa', q: "Which of the following are phases of an OSHA on-site inspection? (Select all that apply)", options: ["Opening conference", "Penalty negotiation", "Walkaround", "Closing conference"], answers: [0, 2, 3], explain: "An OSHA inspection consists of three phases: Opening conference, Walkaround, and Closing conference. Penalty negotiation occurs after the inspection, not during it.", moduleRef: 1, moduleName: "Introduction to OSHA" },
  ],

  2: [
    // Module 2 — Managing Safety & Health
    // MULTIPLE CHOICE (35)
    { type: 'mc', q: "Which of the following is the MOST effective control in the Hierarchy of Controls?", options: ["PPE", "Administrative controls", "Engineering controls", "Elimination"], a: 3, explain: "Elimination — removing the hazard entirely — is the most effective control in the hierarchy.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the following is the LEAST effective control in the Hierarchy of Controls?", options: ["Substitution", "Engineering controls", "Administrative controls", "PPE"], a: 3, explain: "PPE is the least effective control because it does not eliminate the hazard; it only protects the worker from exposure.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "In the Hierarchy of Controls, what does 'Substitution' mean?", options: ["Removing the hazard entirely", "Replacing the hazard with something less dangerous", "Installing barriers or guards", "Changing work procedures"], a: 1, explain: "Substitution means replacing a hazardous process, chemical, or equipment with a less hazardous alternative.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A Job Hazard Analysis (JHA) involves:", options: ["Reviewing past injury records only", "Breaking a job into steps, identifying hazards, and assigning controls", "Conducting annual audits", "Interviewing workers about their pay"], a: 1, explain: "A JHA systematically breaks a job into its basic steps, identifies hazards at each step, and recommends controls.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Near-miss reporting is considered a:", options: ["Lagging indicator", "Reactive indicator", "Leading indicator", "Compliance indicator"], a: 2, explain: "Near-miss reporting is a leading (proactive) indicator — it identifies hazards before injuries occur.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "The TRIR formula uses which hours-worked multiplier?", options: ["100,000", "200,000", "500,000", "1,000,000"], a: 1, explain: "TRIR = (Number of recordable incidents × 200,000) ÷ Total hours worked. 200,000 represents 100 employees working 40 hrs/week for 50 weeks.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A competent person is defined as someone who:", options: ["Has a college degree in safety", "Can identify hazards AND has authority to correct them", "Is certified by OSHA directly", "Has 10+ years of experience"], a: 1, explain: "An OSHA competent person is one who can identify existing and predictable hazards and has the authority to take corrective measures.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A qualified person differs from a competent person because a qualified person:", options: ["Has authority to shut down a job", "Has training or certification to solve specific technical problems", "Reports to OSHA directly", "Must be licensed by the state"], a: 1, explain: "A qualified person has a recognized degree, certificate, or extensive experience to solve or resolve problems related to a subject.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the following is a lagging indicator of safety performance?", options: ["Number of toolbox talks conducted", "Near-miss rate", "Lost-time injury rate", "Percentage of workers trained"], a: 2, explain: "Lagging indicators are reactive and measure outcomes after incidents occur, such as injury rates and fatalities.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "The OSHA 301 Incident Report must be completed within:", options: ["24 hours", "3 days", "7 days", "30 days"], a: 2, explain: "The OSHA 301 must be completed within 7 days of a recordable incident.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the four elements of an effective safety program involves identifying and assessing workplace hazards?", options: ["Management Leadership", "Hazard ID & Assessment", "Education & Training", "Hazard Prevention & Control"], a: 1, explain: "Hazard Identification and Assessment is the second element and focuses on finding and evaluating hazards.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Toolbox talks are best described as:", options: ["Annual safety audits", "Brief daily or weekly safety meetings", "OSHA-required training sessions", "Formal incident investigations"], a: 1, explain: "Toolbox talks are short, informal safety meetings (usually 10-15 minutes) held daily or weekly to review safety topics.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "What does PPE stand for?", options: ["Personal Protective Equipment", "Primary Prevention Element", "Protective Personnel Evaluation", "Personal Prevention Essentials"], a: 0, explain: "PPE stands for Personal Protective Equipment — items worn to minimize exposure to hazards.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Engineering controls reduce hazards by:", options: ["Providing workers with protective gear", "Changing work schedules to limit exposure", "Physically modifying the work environment or equipment", "Training workers to avoid hazards"], a: 2, explain: "Engineering controls physically change the environment or equipment (e.g., guards, ventilation) to reduce hazard exposure.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Administrative controls reduce hazards by:", options: ["Installing machine guards", "Replacing hazardous chemicals", "Changing work practices and procedures", "Providing PPE"], a: 2, explain: "Administrative controls change the way work is done — including procedures, schedules, and worker rotation — to reduce exposure.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which OSHA form is used to log all recordable work-related injuries and illnesses?", options: ["OSHA 300", "OSHA 300A", "OSHA 301", "OSHA 302"], a: 0, explain: "The OSHA 300 Log is the record of all work-related recordable injuries and illnesses.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "An injury is OSHA recordable if it results in:", options: ["First aid treatment only", "Days away from work, restricted duty, or medical treatment beyond first aid", "Any doctor visit, including routine checkups", "A worker complaint to a supervisor"], a: 1, explain: "A case is OSHA recordable if it results in days away from work, job transfer, restricted work, medical treatment beyond first aid, loss of consciousness, or diagnosis of a significant injury by a healthcare professional.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "The four elements of an effective safety and health program are:", options: ["Management Leadership; Hazard ID & Assessment; Hazard Prevention & Control; Education & Training", "PPE; Training; Inspections; Recordkeeping", "Planning; Doing; Checking; Acting", "Policy; Procedures; Practice; Performance"], a: 0, explain: "OSHA's recommended safety and health program framework has four core elements: Management Leadership, Hazard ID & Assessment, Hazard Prevention & Control, and Education & Training.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which indicator type helps predict future incidents before they happen?", options: ["Lagging indicators", "Reactive indicators", "Leading indicators", "Outcome indicators"], a: 2, explain: "Leading indicators are proactive measures that predict and prevent future incidents (e.g., training completion, near-miss reports, safety audits).", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "When should a JHA be updated?", options: ["Never — once completed it is permanent", "Only after a serious injury occurs", "When a job changes, new hazards are identified, or after an incident", "Every 10 years"], a: 2, explain: "A JHA should be reviewed and updated whenever the job changes, new hazards are introduced, or after any incident or near-miss.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the following is an example of a leading safety indicator?", options: ["Number of lost workdays", "OSHA recordable injury rate", "Number of toolbox talks completed", "Workers' compensation costs"], a: 2, explain: "Number of toolbox talks is a proactive (leading) indicator. Lost workdays, injury rates, and compensation costs are all lagging indicators.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Management leadership in a safety program primarily means:", options: ["Letting workers develop their own safety rules", "Demonstrating commitment to safety through actions and resources", "Hiring a safety officer to handle all safety matters", "Posting the OSHA poster"], a: 1, explain: "Management leadership means visibly demonstrating commitment — providing resources, setting expectations, and participating in safety activities.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which step comes FIRST in developing a Job Hazard Analysis?", options: ["Assign hazard controls", "Identify hazards at each step", "Break the job into sequential basic steps", "Interview injured workers"], a: 2, explain: "The first step in a JHA is to break the job down into its basic steps before hazards can be identified and controls assigned.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "OSHA 300A must be signed by which company official?", options: ["The safety officer", "The highest-ranking company executive at the establishment", "Any supervisory employee", "The OSHA compliance officer"], a: 1, explain: "The OSHA 300A must be certified by the highest-ranking company official at the establishment, such as an owner, officer, or executive.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A company with a TRIR of 0 over the past year means:", options: ["They had no fatalities", "They had no OSHA recordable injuries or illnesses", "They had no lost-time injuries", "They are exempt from OSHA inspections"], a: 1, explain: "A TRIR of 0 means there were zero recordable injuries or illnesses during the measurement period.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which control would be most effective for eliminating silica dust exposure during concrete grinding?", options: ["Dust mask (N95)", "Work rotation schedule", "Wet methods or local exhaust ventilation", "Posting warning signs"], a: 2, explain: "Wet methods and local exhaust ventilation are engineering controls — higher in the hierarchy than administrative controls or PPE.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Safety and health training under OSHA must be conducted:", options: ["In English only", "In a language and vocabulary workers can understand", "Solely through written materials", "Once upon initial hire, never repeated"], a: 1, explain: "OSHA requires that training be delivered in a language and at a vocabulary level the worker can understand.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A written safety and health program is required for employers with:", options: ["Any number of employees in high-hazard industries", "50 or more employees only", "100 or more employees", "Only unionized workforces"], a: 0, explain: "Many OSHA standards require written programs for employers in applicable industries, regardless of size, particularly in high-hazard sectors like construction.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the following is the correct order of the Hierarchy of Controls from most to least effective?", options: ["PPE → Administrative → Engineering → Substitution → Elimination", "Elimination → Substitution → Engineering → Administrative → PPE", "Engineering → Elimination → Administrative → Substitution → PPE", "Administrative → Substitution → PPE → Engineering → Elimination"], a: 1, explain: "From most to least effective: Elimination, Substitution, Engineering Controls, Administrative Controls, PPE.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which of the following best defines 'hazard' in safety terminology?", options: ["An injury that has already occurred", "A condition or practice that has potential to cause harm", "A violation of OSHA regulations", "An unsafe worker behavior only"], a: 1, explain: "A hazard is any condition, practice, or behavior with the potential to cause injury, illness, or property damage.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "An OSHA 300 Log must be maintained by employers with:", options: ["1 or more employees", "10 or more employees", "More than 10 employees (11+)", "25 or more employees"], a: 2, explain: "Employers with more than 10 employees (11 or more) in most industries must maintain OSHA 300 Logs. Certain low-hazard industries are partially exempt.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Which element of a safety program focuses on educating workers about hazards and safe work practices?", options: ["Management Leadership", "Hazard Prevention & Control", "Hazard ID & Assessment", "Education & Training"], a: 3, explain: "Education and Training ensures workers have the knowledge and skills to recognize hazards and work safely.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "A near-miss is best described as:", options: ["An incident that caused an injury", "An event that could have resulted in injury but did not", "A first aid case", "A close call that requires OSHA reporting"], a: 1, explain: "A near-miss is an unplanned event that did not result in injury, illness, or damage but had the potential to do so.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "Injury rate data, fatality statistics, and days away from work are examples of:", options: ["Leading indicators", "Proactive metrics", "Lagging indicators", "Real-time indicators"], a: 2, explain: "These are all lagging indicators — reactive metrics that measure outcomes after events have occurred.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'mc', q: "The Hierarchy of Controls is important because it:", options: ["Tells workers what PPE to buy", "Guides employers to select the most effective risk-reduction methods", "Replaces OSHA standards", "Is required only on federal construction projects"], a: 1, explain: "The Hierarchy of Controls helps prioritize hazard control methods from most to least effective, ensuring the best available protection is used.", moduleRef: 2, moduleName: "Managing Safety & Health" },

    // FILL IN THE BLANK (8)
    { type: 'fib', q: "The Hierarchy of Controls lists ___ as the most effective method to reduce hazards.", answer: "Elimination", accept: ["elimination"], explain: "Elimination — removing the hazard entirely — is the most effective level of the Hierarchy of Controls.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "TRIR stands for Total ___ Incident Rate.", answer: "Recordable", accept: ["recordable incident rate"], explain: "TRIR = Total Recordable Incident Rate, calculated as (recordable incidents × 200,000) / hours worked.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "A ___ person is defined by OSHA as someone who can identify hazards and has the authority to correct them.", answer: "competent", accept: ["competent person"], explain: "OSHA's competent person must both be able to identify hazards and have the authority to take corrective action.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "Near-miss reporting is an example of a ___ indicator.", answer: "leading", accept: ["proactive"], explain: "Leading indicators are proactive measures used to anticipate and prevent incidents before they happen.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "The OSHA 301 Incident Report must be completed within ___ days of a recordable incident.", answer: "7", accept: ["seven"], explain: "OSHA requires the 301 to be completed within 7 days of a recordable work-related injury or illness.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "The TRIR formula multiplies the number of recordable incidents by ___ and divides by hours worked.", answer: "200,000", accept: ["200000"], explain: "The 200,000 figure represents the equivalent of 100 employees working 40 hours per week for 50 weeks.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "PPE is considered the ___ resort in the Hierarchy of Controls.", answer: "last", accept: ["least effective", "last resort"], explain: "PPE is the least effective control and should only be used when higher-order controls are not feasible.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'fib', q: "Brief daily or weekly safety meetings on a construction site are commonly called ___ talks.", answer: "toolbox", accept: ["tool box", "toolbox talks"], explain: "Toolbox talks are short, focused safety meetings conducted at the worksite, often at the start of a shift.", moduleRef: 2, moduleName: "Managing Safety & Health" },

    // SELECT ALL THAT APPLY (7)
    { type: 'sa', q: "Which of the following are part of the Hierarchy of Controls? (Select all that apply)", options: ["Elimination", "Litigation", "Engineering controls", "PPE"], answers: [0, 2, 3], explain: "Elimination, Engineering controls, and PPE are all levels in the Hierarchy of Controls. Litigation is not a hazard control method.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following are leading safety indicators? (Select all that apply)", options: ["Number of safety audits completed", "Lost-time injury rate", "Near-miss reports submitted", "Workers' compensation costs"], answers: [0, 2], explain: "Safety audits and near-miss reports are proactive (leading) indicators. Lost-time injury rates and workers' comp costs are lagging indicators.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following are the four elements of an effective safety program? (Select all that apply)", options: ["Management Leadership", "Hazard ID & Assessment", "Employee Discipline", "Education & Training"], answers: [0, 1, 3], explain: "The four elements are Management Leadership, Hazard ID & Assessment, Hazard Prevention & Control, and Education & Training. Employee Discipline is not one of the four elements.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following cases are OSHA recordable? (Select all that apply)", options: ["Days away from work", "First aid treatment only", "Medical treatment beyond first aid", "Loss of consciousness"], answers: [0, 2, 3], explain: "Days away from work, medical treatment beyond first aid, and loss of consciousness are all recordable criteria. First aid only is not recordable.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following are steps in a Job Hazard Analysis (JHA)? (Select all that apply)", options: ["Break job into basic steps", "Identify hazards at each step", "File an OSHA complaint", "Recommend hazard controls"], answers: [0, 1, 3], explain: "A JHA involves breaking the job into steps, identifying hazards at each step, and recommending controls. Filing an OSHA complaint is not part of the JHA process.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following are OSHA required recordkeeping forms for most employers? (Select all that apply)", options: ["OSHA 300 Log", "OSHA 300A Summary", "OSHA 301 Incident Report", "OSHA 200 Hazard Register"], answers: [0, 1, 2], explain: "The OSHA 300, 300A, and 301 are the three required recordkeeping forms. There is no OSHA 200 Hazard Register.", moduleRef: 2, moduleName: "Managing Safety & Health" },
    { type: 'sa', q: "Which of the following are examples of engineering controls? (Select all that apply)", options: ["Machine guarding", "Work rotation schedules", "Local exhaust ventilation", "Wet methods for dust control"], answers: [0, 2, 3], explain: "Machine guarding, local exhaust ventilation, and wet methods are engineering controls that physically reduce hazards. Work rotation is an administrative control.", moduleRef: 2, moduleName: "Managing Safety & Health" },
  ],

  3: [
    // Module 3 — Focus Four: Fall Hazards
    // MULTIPLE CHOICE (35)
    { type: 'mc', q: "Falls account for approximately what percentage of construction fatalities?", options: ["15%", "25%", "36%", "50%"], a: 2, explain: "Falls are the leading cause of construction deaths, accounting for approximately 36% of construction fatalities.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "At what height above a lower level is fall protection required in construction?", options: ["4 feet", "6 feet", "10 feet", "15 feet"], a: 1, explain: "OSHA 1926.502 requires fall protection for construction workers at heights of 6 feet or more above a lower level.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Which of the following is NOT one of the three OSHA-accepted fall protection systems?", options: ["Guardrail system", "Safety net system", "Personal fall arrest system (PFAS)", "Ladder safety system"], a: 3, explain: "The three OSHA-accepted fall protection systems are guardrails, safety nets, and personal fall arrest systems. A ladder safety system is a separate category.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the required height of the top rail of a guardrail system in construction?", options: ["36 inches ± 3 inches", "42 inches ± 3 inches", "48 inches ± 3 inches", "54 inches ± 3 inches"], a: 1, explain: "The top rail must be 42 inches plus or minus 3 inches (39–45 inches) above the walking/working surface.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "The midrail of a guardrail system must be located:", options: ["12 inches below the top rail", "At approximately 21 inches above the walking surface", "At 36 inches above the walking surface", "At the worker's waist level"], a: 1, explain: "The midrail must be installed at approximately the midpoint between the top rail and the walking surface — approximately 21 inches.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the minimum height of a toeboard on a guardrail system?", options: ["2 inches", "3 inches", "3.5 inches", "4 inches"], a: 2, explain: "Toeboards must be at least 3.5 inches (3½ inches) high to prevent tools and materials from rolling off edges.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "The top rail of a guardrail system must withstand how many pounds of force applied in any downward or outward direction?", options: ["100 lbs", "150 lbs", "200 lbs", "250 lbs"], a: 2, explain: "OSHA requires the top rail to withstand at least 200 pounds of force applied in any downward or outward direction.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Safety nets must be installed within how many feet below the working surface?", options: ["15 feet", "20 feet", "25 feet", "30 feet"], a: 3, explain: "Safety nets must be installed as close as practicable under the working surface, but no more than 30 feet below it.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Floor holes and openings with a minimum dimension of ___ or more must be covered or guarded.", options: ["1 inch", "2 inches", "4 inches", "6 inches"], a: 1, explain: "Holes 2 inches or more in their least dimension must be covered or protected with a guardrail.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Hole covers must be capable of supporting:", options: ["The weight of one worker", "At least twice the maximum intended load", "1,000 lbs minimum", "500 lbs per square foot"], a: 1, explain: "OSHA requires hole covers to support at least twice the weight of employees, equipment, and materials that may be imposed on them.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A Personal Fall Arrest System (PFAS) must use which body support?", options: ["Body belt only", "Chest harness", "Full-body harness", "Either a body belt or full-body harness"], a: 2, explain: "Body belts may only be used for positioning/restraint. Fall arrest systems require a full-body harness.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the maximum free fall distance allowed in a PFAS?", options: ["3 feet", "4 feet", "6 feet", "10 feet"], a: 2, explain: "A PFAS must be rigged so that a worker cannot free fall more than 6 feet.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the maximum arresting force allowed on a worker in a PFAS?", options: ["900 lbs", "1,800 lbs", "2,500 lbs", "5,000 lbs"], a: 1, explain: "The maximum arresting force on a worker in a PFAS must not exceed 1,800 pounds.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Anchor points for a PFAS must be capable of supporting at least:", options: ["1,800 lbs", "3,000 lbs", "5,000 lbs per attached worker", "2× the intended load"], a: 2, explain: "PFAS anchorages must support at least 5,000 pounds per attached worker.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Where should the D-ring of a full-body harness be positioned?", options: ["Front of the chest", "Center of the back between the shoulder blades", "Left shoulder", "Hip level"], a: 1, explain: "The D-ring attachment point should be positioned in the center of the worker's back, between the shoulder blades.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A body belt may only be used for:", options: ["Fall arrest", "Fall restraint or positioning", "Attachment to a safety net", "Ladder climbing"], a: 1, explain: "Body belts can only be used for positioning or restraint systems — not fall arrest — because they can cause internal injury during a fall.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "On a low-slope roof (slope of 4:12 or less), which fall protection method is acceptable?", options: ["No protection needed below 10 feet", "Warning line system alone", "Warning line system combined with a safety monitor", "Guardrail only"], a: 2, explain: "On low-slope roofs, OSHA allows a combination of a warning line system and a safety monitor as an alternative fall protection method.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the minimum tensile strength of a warning line?", options: ["200 lbs", "350 lbs", "500 lbs", "1,000 lbs"], a: 2, explain: "Warning lines must have a minimum tensile strength of 500 pounds.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A warning line must be erected at least how many feet from the roof edge?", options: ["3 feet", "6 feet", "10 feet", "15 feet"], a: 1, explain: "Warning lines must be erected no less than 6 feet from the roof edge.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What does fall restraint prevent?", options: ["A worker from being injured in a fall", "A worker from reaching the fall hazard edge", "The impact force during a fall", "A worker from entering a hazard zone"], a: 1, explain: "Fall restraint systems prevent the worker from reaching the unprotected edge — the worker cannot get close enough to fall.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A Controlled Access Zone (CAZ) is used primarily for:", options: ["Excavation work", "Leading edge work and precast concrete erection", "Roofing on residential homes only", "Scaffolding assembly"], a: 1, explain: "CAZs are designated areas used for leading edge work and certain other operations where conventional fall protection is not feasible.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the drop-test requirement for safety nets?", options: ["A 200 lb bag dropped 13 feet", "A 400 lb bag dropped 26 feet", "A 400 lb bag dropped 30 feet", "A 250 lb bag dropped 20 feet"], a: 1, explain: "Safety nets must pass a drop test using a 400-pound bag dropped from 26 feet (or from the highest surface from which the net would be used, if lower).", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Which of the following is an example of a self-retracting lanyard (SRL) benefit?", options: ["It replaces the need for anchor points", "It reduces free fall distance", "It can be used as a body belt", "It allows falls greater than 6 feet"], a: 1, explain: "An SRL limits and reduces free fall distance because it locks quickly when sudden movement is detected.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Hole covers must be labeled with which word(s)?", options: ["DANGER", "OPEN", "HOLE or COVER", "FALL HAZARD"], a: 2, explain: "OSHA requires hole covers to be marked with the word 'HOLE' or 'COVER' to warn workers of the hazard.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A low-slope roof is defined as having a slope of:", options: ["2:12 or less", "4:12 or less", "6:12 or less", "8:12 or less"], a: 1, explain: "OSHA defines a low-slope roof as one with a slope of 4:12 or less.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "When must a PFAS be inspected?", options: ["Annually by a manufacturer rep", "Before each use by the worker", "Monthly by a competent person", "Only after a fall event"], a: 1, explain: "Workers should inspect their PFAS components before each use to ensure there is no damage, wear, or defects.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What happens to a full-body harness after it has arrested a fall?", options: ["It may be reused after visual inspection", "It must be removed from service and replaced", "It should be inspected by the manufacturer and returned if undamaged", "It can be reused once by another worker"], a: 1, explain: "After arresting a fall, a harness must be removed from service immediately, even if no visible damage is evident.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "OSHA's fall protection standard for construction is found in:", options: ["1926.200", "1926.350", "1926.502", "1926.600"], a: 2, explain: "OSHA's fall protection requirements for construction are located in 29 CFR 1926.502.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "What is the difference between fall arrest and fall restraint?", options: ["Arrest uses guardrails; restraint uses nets", "Arrest stops a fall after it starts; restraint prevents reaching the edge", "Arrest is passive; restraint is active", "There is no difference"], a: 1, explain: "Fall arrest systems stop a worker after a fall begins; fall restraint systems prevent the worker from ever reaching the edge where a fall could occur.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A deceleration device in a PFAS is designed to:", options: ["Attach to the anchor point", "Slow the worker's fall and limit arresting force", "Replace the lanyard", "Signal an alarm during a fall"], a: 1, explain: "A deceleration device absorbs energy during a fall, limiting the arresting force imposed on the worker's body.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Falls in construction are ranked as the:", options: ["#1 cause of construction deaths", "#2 cause of construction deaths", "#3 cause of construction deaths", "#4 cause of construction deaths"], a: 0, explain: "Falls are consistently the #1 cause of construction deaths in the United States.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Which of the following activities would require fall protection at 6 feet in construction?", options: ["Working on a scaffold 5 feet high", "Digging a 6-foot-deep trench", "Working on a mezzanine 6 feet above the floor", "Climbing a fixed ladder"], a: 2, explain: "Working on a mezzanine 6 feet above the lower level requires fall protection under OSHA 1926.502.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Leading edges in construction present fall hazards because:", options: ["They are located near electrical equipment", "The edge of the work surface extends beyond the existing floor and lacks permanent fall protection", "Workers must kneel near them", "Material deliveries are made near the edge"], a: 1, explain: "Leading edges are the advancing edges of a floor or deck under construction — they change daily and do not have permanent guardrails.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "Which component of a PFAS connects the harness to the anchor point?", options: ["Deceleration device only", "Lanyard or self-retracting lanyard", "D-ring", "Toeboard"], a: 1, explain: "The lanyard (or SRL) is the connecting component between the body harness and the anchor point.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'mc', q: "A safety monitor must be:", options: ["A certified OSHA inspector", "A competent person with no other duties while monitoring", "A worker with at least 5 years of experience", "A supervisor only"], a: 1, explain: "A safety monitor must be a competent person who is fully dedicated to monitoring workers and has no other duties while serving as monitor.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },

    // FILL IN THE BLANK (8)
    { type: 'fib', q: "OSHA requires fall protection in construction when workers are at ___ feet or more above a lower level.", answer: "6", accept: ["six"], explain: "29 CFR 1926.502 establishes 6 feet as the height trigger for fall protection in construction.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "The top rail of a guardrail system must be ___ inches high, plus or minus 3 inches.", answer: "42", accept: ["forty-two", "forty two"], explain: "OSHA requires the top rail to be 42 inches (±3 inches) above the walking/working surface.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "The maximum free fall distance in a Personal Fall Arrest System is ___ feet.", answer: "6", accept: ["six"], explain: "A PFAS must be rigged so that workers cannot free fall more than 6 feet.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "PFAS anchor points must support at least ___ pounds per attached worker.", answer: "5,000", accept: ["5000", "five thousand"], explain: "OSHA requires PFAS anchorages to withstand at least 5,000 pounds per attached worker.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "Safety nets must be installed no more than ___ feet below the working surface.", answer: "30", accept: ["thirty"], explain: "OSHA requires safety nets to be installed within 30 feet below the working surface.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "Holes with a minimum dimension of ___ inches or more must be covered or guarded.", answer: "2", accept: ["two"], explain: "Floor holes and openings measuring 2 inches or more must be covered or protected with guardrails.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "The D-ring of a full-body harness must be positioned in the ___ of the back.", answer: "center", accept: ["middle", "center of the back", "between the shoulder blades"], explain: "The D-ring attachment point must be located in the center of the back, between the shoulder blades.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'fib', q: "A body belt may only be used for fall ___, not fall arrest.", answer: "restraint", accept: ["positioning", "restraint or positioning"], explain: "Body belts cannot withstand the forces of a fall arrest; they are limited to positioning and restraint uses only.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },

    // SELECT ALL THAT APPLY (7)
    { type: 'sa', q: "Which of the following are OSHA-accepted fall protection systems in construction? (Select all that apply)", options: ["Guardrail system", "Safety net system", "Personal fall arrest system", "Safety monitor alone"], answers: [0, 1, 2], explain: "The three accepted fall protection systems are guardrails, safety nets, and PFAS. A safety monitor alone is not sufficient except in limited roofing situations combined with a warning line.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following are components of a Personal Fall Arrest System? (Select all that apply)", options: ["Full-body harness", "Anchor point", "Toeboard", "Lanyard or SRL"], answers: [0, 1, 3], explain: "A PFAS consists of a full-body harness, an anchor point capable of supporting 5,000 lbs, and a connecting means such as a lanyard or SRL. Toeboards are part of guardrail systems.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following are requirements for guardrail systems in construction? (Select all that apply)", options: ["Top rail at 42 inches ± 3 inches", "Toeboard at least 3.5 inches high", "Top rail must withstand 200 lbs", "Top rail must be bright orange"], answers: [0, 1, 2], explain: "Guardrails must have a 42-inch (±3) top rail, 3.5-inch minimum toeboard, and withstand 200 lbs of force. There is no color requirement under OSHA.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following are examples of fall protection that require 6-foot trigger height in construction? (Select all that apply)", options: ["Unprotected edges and sides", "Floor openings/holes ≥2 inches", "Excavations", "Formwork and reinforcing steel"], answers: [0, 3], explain: "Unprotected edges and formwork/reinforcing steel work require fall protection at 6 feet. Floor holes ≥2 inches require covers at any height. Excavations follow different rules.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following statements about safety nets are correct? (Select all that apply)", options: ["Must be within 30 feet below the work surface", "Drop test uses a 400 lb bag from 26 feet", "Can replace all other fall protection methods", "Must have border ropes with a minimum 5,000 lb breaking strength"], answers: [0, 1, 3], explain: "Safety nets must be within 30 feet, pass the 400 lb/26 ft drop test, and have border ropes with 5,000 lb breaking strength. They cannot replace all other methods in all situations.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following are true about hole covers? (Select all that apply)", options: ["Must be labeled 'HOLE' or 'COVER'", "Must support twice the maximum intended load", "Must be painted yellow", "Must be secured to prevent displacement"], answers: [0, 1, 3], explain: "Hole covers must be labeled HOLE or COVER, support twice the maximum load, and be secured against accidental displacement. OSHA does not require yellow color.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
    { type: 'sa', q: "Which of the following are true about fall restraint systems? (Select all that apply)", options: ["They prevent a worker from reaching the fall hazard", "They stop a worker after a fall has begun", "The lanyard length must be set to prevent reaching the edge", "They can use a body belt"], answers: [0, 2, 3], explain: "Fall restraint prevents reaching the edge (not arrests a fall), requires a properly set lanyard length, and can use a body belt. Fall arrest stops a fall after it starts.", moduleRef: 3, moduleName: "Focus Four: Fall Hazards" },
  ],

  4: [
    // Module 4 — Focus Four: Electrical Hazards
    // MULTIPLE CHOICE (35)
    { type: 'mc', q: "Electrical hazards are ranked as which leading cause of construction deaths?", options: ["#1", "#2", "#3", "#4"], a: 2, explain: "Electrical hazards are the #3 cause of construction fatalities in the United States.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "GFCI protection is required on which type of temporary wiring in construction?", options: ["All 240V circuits", "120V, 15-20 amp receptacles", "Only circuits over 100 amps", "Permanently installed wiring only"], a: 1, explain: "OSHA 1926.404 requires GFCI protection on all 120-volt, single-phase, 15- and 20-ampere receptacles on construction sites.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "A GFCI device will trip when it detects a current imbalance of:", options: ["1 milliamp", "5 milliamps", "10 milliamps", "50 milliamps"], a: 1, explain: "A GFCI trips when it detects a ground fault current imbalance of approximately 5 milliamps (mA).", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "What current level can cause ventricular fibrillation?", options: ["5 mA", "10–15 mA", "50–100 mA", "200 mA"], a: 2, explain: "Ventricular fibrillation — a potentially fatal heart arrhythmia — can occur at currents as low as 50-100 milliamps.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "The minimum required clearance from overhead power lines for voltages up to 50kV is:", options: ["5 feet", "8 feet", "10 feet", "15 feet"], a: 2, explain: "OSHA requires workers and equipment to maintain at least 10 feet of clearance from overhead power lines rated 50kV or below.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "What is the alternative to using a GFCI on a construction site?", options: ["Use heavy-duty extension cords", "Assured Equipment Grounding Conductor Program (AEGCP)", "Double-insulated tools only", "Ground fault breakers in the main panel"], a: 1, explain: "The AEGCP is the only OSHA-approved alternative to GFCI protection on construction sites.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Double-insulated power tools are identified by:", options: ["A red stripe on the cord", "A square within a square symbol", "A yellow housing", "Three prongs on the plug"], a: 1, explain: "Double-insulated tools are marked with a square-within-a-square symbol, indicating two layers of insulation instead of grounding.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Double-insulated tools:", options: ["Must be grounded with a 3-prong plug", "Do not require grounding because of their double insulation", "Are only approved for outdoor use", "Must be inspected by OSHA annually"], a: 1, explain: "Because they have two independent layers of insulation, double-insulated tools do not require a ground prong or external grounding.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "OSHA's LOTO (Lockout/Tagout) standard for construction is found in:", options: ["1926.400", "1926.404", "1926.417", "1926.502"], a: 2, explain: "OSHA's Lockout/Tagout requirements for construction are found in 29 CFR 1926.417.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Under LOTO procedures, each worker performing maintenance must:", options: ["Share one group lock with their supervisor", "Apply their own personal lock to the energy isolation point", "Verbally notify the foreman before starting work", "Rely on tagout only"], a: 1, explain: "Each authorized worker must apply their own personal lock to the energy-isolating device to ensure individual protection.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Why is tagout alone considered less safe than lockout?", options: ["Tags are more expensive than locks", "Tags can be inadvertently removed and do not physically prevent re-energization", "Tagout requires more paperwork", "Tags must be approved by OSHA"], a: 1, explain: "Tags only provide a warning — they can be removed or ignored. Locks physically prevent the energy isolation device from being re-engaged.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Bonding of electrical equipment refers to:", options: ["Connecting two circuits together to share current", "Connecting metal parts together to create equal electrical potential", "Taping wire connections for insulation", "Grounding a circuit to earth"], a: 1, explain: "Bonding connects conductive metal parts so there is no potential difference between them, preventing shock from contact.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Extension cords used on construction sites must be:", options: ["2-prong polarized cords", "Three-prong grounded, undamaged, and properly rated for the load", "Rated only for 15 amps", "At least 25 feet long"], a: 1, explain: "Extension cords on construction sites must be 3-prong grounded, in good condition, and of the proper gauge for the electrical load.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "An arc flash hazard is dangerous because:", options: ["It only occurs in high-voltage systems above 480V", "It can cause severe burns, fire, and fatality even without direct contact", "It is limited to outdoor transmission lines only", "It only affects ungrounded equipment"], a: 1, explain: "An arc flash releases tremendous energy in the form of heat, light, and pressure — capable of causing severe burns and death at considerable distances.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Before maintaining or repairing electrical equipment, workers must:", options: ["Wear rubber gloves only", "De-energize the equipment and apply LOTO", "Notify the nearest hospital", "Use a two-prong adapter"], a: 1, explain: "OSHA requires electrical equipment to be de-energized and locked/tagged out before any maintenance or repair work begins.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which of the following temporary lighting requirements applies in wet locations?", options: ["Standard metal sockets are acceptable", "Vapor-proof, non-metallic sockets must be used", "Fluorescent lights are prohibited", "All lighting must be battery powered"], a: 1, explain: "In wet or damp locations, temporary lighting must use vapor-proof fixtures and non-metallic sockets.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "What does GFCI stand for?", options: ["Ground Fault Circuit Indicator", "Ground Fault Circuit Interrupter", "General Fault Current Insulator", "Ground Fault Control Interface"], a: 1, explain: "GFCI stands for Ground Fault Circuit Interrupter — a device that detects current leakage to ground and interrupts the circuit.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which current level is typically the threshold for 'let-go' — where a person can no longer release their grip?", options: ["1–3 mA", "5 mA", "10–16 mA", "50 mA"], a: 2, explain: "At 10–16 mA, muscle contractions may prevent a person from releasing their grip on an energized conductor.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "The four main electrical hazards in construction are:", options: ["Electrocution, arc flash, overload, and short circuit", "Electrocution, electric shock, burns, and arc flash/blast", "Shock, fire, explosion, and voltage drop", "Resistance, voltage, current, and power"], a: 1, explain: "OSHA identifies the four main electrical hazards as electrocution, electric shock, electrical burns, and arc flash/blast.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "What is the primary purpose of an Assured Equipment Grounding Conductor Program?", options: ["To eliminate the need for GFCI entirely on all sites", "To ensure all tools and extension cords have functioning ground conductors through inspection and testing", "To replace LOTO requirements", "To test voltage levels on all circuits"], a: 1, explain: "The AEGCP involves a written program, visual inspection before each use, and systematic testing to ensure grounding conductors are intact and functional.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which of the following is an example of a step potential hazard?", options: ["A worker touching a live wire", "Current flowing through the ground near a downed power line, creating voltage differences between footsteps", "A worker receiving a shock from a 120V outlet", "Contact with an arc flash"], a: 1, explain: "Step potential occurs when a downed power line energizes the ground; voltage differences between a worker's feet can complete a circuit through their body.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Electrical equipment must be listed and labeled by a Nationally Recognized Testing Laboratory (NRTL). An example of an NRTL is:", options: ["OSHA", "NIOSH", "UL (Underwriters Laboratories)", "ANSI"], a: 2, explain: "UL (Underwriters Laboratories) is a well-known NRTL. OSHA recognizes NRTLs as organizations that test and certify equipment to safety standards.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "When working near underground utilities, workers must first:", options: ["Post a lookout", "Dig carefully with shovels only", "Contact 811 (Call Before You Dig) to locate utilities", "Apply LOTO to all nearby panels"], a: 2, explain: "Before excavating, workers must call 811 to have underground utilities located and marked to prevent accidental contact.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "The resistance of the human body that OSHA typically cites for shock calculation purposes is approximately:", options: ["100 ohms", "500 ohms", "1,000 ohms (1 kΩ)", "10,000 ohms"], a: 2, explain: "OSHA typically uses approximately 1,000 ohms as the resistance of the human body for electrical hazard calculations, though actual resistance varies.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which of the following is prohibited when using extension cords on a construction site?", options: ["Using a 3-prong grounded cord", "Running the cord through a doorway with the cord pinched by the door", "Using a cord rated for the load", "Inspecting the cord before each use"], a: 1, explain: "Extension cords must not be run through doors, windows, or walls where they can be pinched, damaged, or create a trip/shock hazard.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "OSHA's electrical safety standard for construction is primarily found in:", options: ["29 CFR 1926 Subpart E", "29 CFR 1926 Subpart K", "29 CFR 1910.147", "29 CFR 1926 Subpart P"], a: 1, explain: "Electrical standards for construction are found in 29 CFR 1926 Subpart K (Electrical).", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "A ground fault occurs when:", options: ["A circuit is overloaded with too many devices", "Current flows outside its intended path, usually through a person or ground", "A fuse blows due to high resistance", "Two circuits are connected in parallel"], a: 1, explain: "A ground fault is an unintended path for current — often through a person touching a live conductor — back to ground.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Workers should never use damaged extension cords because:", options: ["They may overload the circuit breaker", "Damaged insulation can expose live conductors and create shock or fire hazards", "They reduce tool performance", "OSHA requires new cords monthly"], a: 1, explain: "Damaged extension cords expose live wires, increasing the risk of electric shock, electrocution, and fire.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "What does 'de-energize' mean in electrical safety?", options: ["Reduce voltage to a safe level", "Disconnect the equipment from all energy sources and verify zero energy state", "Install a GFCI on the circuit", "Turn off the main breaker temporarily"], a: 1, explain: "De-energizing means completely disconnecting the equipment from all energy sources, releasing stored energy, and verifying zero energy before work begins.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Using a tool with a missing ground prong on a construction site:", options: ["Is acceptable if the tool has a GFCI outlet", "Violates OSHA requirements and removes shock protection", "Is acceptable for double-insulated tools only", "Is permitted temporarily if supervised"], a: 1, explain: "Tools with missing or damaged ground prongs must not be used — the ground connection is a critical safety feature that prevents shock.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "OSHA's LOTO standard requires that before re-energizing equipment, the authorized employee must:", options: ["Notify OSHA first", "Ensure all workers are clear and all locks/tags have been removed", "Test the equipment by turning it on briefly", "Get written approval from management"], a: 1, explain: "Before re-energizing, the authorized employee must verify that all tools are removed, all employees are clear, and that all personal locks and tags have been removed.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which of the following best describes electrical 'grounding'?", options: ["Connecting all metal parts to prevent potential differences", "Providing a low-resistance path for fault current to flow safely to earth", "Installing insulation on all conductors", "Placing equipment on a non-conductive surface"], a: 1, explain: "Grounding provides a low-resistance path for fault current to return to earth, causing the circuit breaker to trip and preventing dangerous voltage buildup on equipment.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Which of the following is true about using ladders near electrical hazards?", options: ["Metal ladders are preferred near power lines", "Only fiberglass or wood ladders should be used near electrical hazards", "Ladders must be within 2 feet of energized parts", "Metal ladders are safe if the worker wears rubber-soled shoes"], a: 1, explain: "Only non-conductive ladders (fiberglass or wood) should be used near electrical equipment or power lines. Metal ladders conduct electricity.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "An employer's AEGCP must include all of the following EXCEPT:", options: ["A written program", "Designated person to implement the program", "Visual inspection of cords and tools before each use", "Monthly OSHA notification of testing results"], a: 3, explain: "The AEGCP requires a written program, a designated responsible person, visual inspection before use, and systematic testing — but does NOT require monthly OSHA notification.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'mc', q: "Electrocution is defined as:", options: ["Electric shock that causes burns", "Death caused by electric current passing through the body", "Any contact with an energized conductor", "Shock causing muscle contraction"], a: 1, explain: "Electrocution specifically refers to death resulting from electric current passing through the body. Electric shock may or may not be fatal.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },

    // FILL IN THE BLANK (8)
    { type: 'fib', q: "GFCI protection is required on all 120V, 15–20 amp temporary receptacles on construction sites per OSHA 1926.___.", answer: "404", accept: ["1926.404"], explain: "29 CFR 1926.404 is the OSHA standard requiring GFCI protection for temporary wiring on construction sites.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "A GFCI device trips when it senses a current imbalance of approximately ___ milliamps.", answer: "5", accept: ["five", "5 mA", "5 milliamps"], explain: "GFCIs are designed to trip at approximately 5 milliamps (mA) of ground fault current.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "The minimum overhead power line clearance distance for voltages up to 50kV is ___ feet.", answer: "10", accept: ["ten"], explain: "Workers and equipment must maintain at least 10 feet of clearance from overhead lines rated 50kV or below.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "The OSHA-approved alternative to GFCI protection on construction sites is the Assured Equipment ___ Conductor Program.", answer: "Grounding", accept: ["grounding conductor", "ground"], explain: "The AEGCP — Assured Equipment Grounding Conductor Program — is the only accepted alternative to GFCI on construction sites.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "Double-insulated tools are identified by the symbol of a ___ within a square.", answer: "square", accept: ["box", "square within a square"], explain: "The double-insulation symbol is a small square inside a larger square, indicating the tool has two independent insulation systems.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "Under LOTO procedures, each worker must apply their ___ personal lock to the energy isolation point.", answer: "own", accept: ["individual", "personal"], explain: "Each authorized employee must apply their own individual lock — not share one — to ensure they personally control the energy source.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "Ventricular fibrillation can be caused by as little as ___ to 100 milliamps of current through the body.", answer: "50", accept: ["fifty", "50 mA"], explain: "Current in the range of 50–100 mA can cause ventricular fibrillation, a potentially fatal cardiac arrhythmia.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'fib', q: "Electrical hazards are the ___ leading cause of construction fatalities.", answer: "third", accept: ["3rd", "#3", "3"], explain: "Electrical fatalities rank #3 among the Focus Four causes of construction deaths.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },

    // SELECT ALL THAT APPLY (7)
    { type: 'sa', q: "Which of the following are electrical hazard types in construction? (Select all that apply)", options: ["Electrocution", "Electric shock", "Electrical burns", "Voltage drop"], answers: [0, 1, 2], explain: "OSHA's four main electrical hazards are electrocution, electric shock, electrical burns, and arc flash/blast. Voltage drop is a power quality issue, not a safety hazard category.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following are requirements for extension cords on a construction site? (Select all that apply)", options: ["Must be 3-prong grounded", "Must be inspected before each use", "Must be at least 50 feet long", "Must be free of damage and defects"], answers: [0, 1, 3], explain: "Extension cords must be 3-prong grounded, inspected before use, and free of damage. There is no minimum length requirement.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following are required elements of a Lockout/Tagout program? (Select all that apply)", options: ["Written energy control procedures", "Each worker applies own lock", "Notification to OSHA before each LOTO", "Verification of zero energy state before work begins"], answers: [0, 1, 3], explain: "LOTO programs require written procedures, individual locks per worker, and verification of zero energy. OSHA notification before each LOTO event is not required.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following are true about GFCI devices? (Select all that apply)", options: ["They trip at approximately 5 mA", "They are required on 120V, 15–20A temporary receptacles", "They eliminate all electrical hazards", "They protect against ground faults"], answers: [0, 1, 3], explain: "GFCIs trip at ~5 mA, are required on 120V 15–20A temp receptacles, and protect against ground faults. They do not eliminate all electrical hazards (e.g., arc flash, overloads).", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following practices help protect workers from electrical hazards? (Select all that apply)", options: ["De-energizing equipment before maintenance", "Using GFCI or AEGCP", "Using metal ladders near power lines", "Maintaining clearance from overhead lines"], answers: [0, 1, 3], explain: "De-energizing, using GFCI/AEGCP, and maintaining clearance protect workers. Metal ladders near power lines are dangerous and prohibited.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following are true about double-insulated tools? (Select all that apply)", options: ["They are marked with a square-within-a-square symbol", "They do not require a ground prong", "They can be used on any circuit including ungrounded circuits", "They provide two independent layers of insulation"], answers: [0, 1, 3], explain: "Double-insulated tools are marked with a square-in-square symbol, don't need grounding, and have two insulation layers. They should still be used on proper circuits.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
    { type: 'sa', q: "Which of the following are steps that must be completed before re-energizing equipment under LOTO? (Select all that apply)", options: ["All employees are clear of the equipment", "All personal locks and tags are removed", "A supervisor verbally approves re-energization", "All tools and materials are removed from the work area"], answers: [0, 1, 3], explain: "Before re-energization: all employees must be clear, all locks/tags removed, and all tools/materials cleared. A supervisor verbal approval alone is not an OSHA LOTO requirement.", moduleRef: 4, moduleName: "Focus Four: Electrical Hazards" },
  ],

  5: [
    // Module 5 — Focus Four: Struck-By Hazards
    // MULTIPLE CHOICE (35)
    { type: 'mc', q: "Struck-by hazards are ranked as which leading cause of construction deaths?", options: ["#1", "#2", "#3", "#4"], a: 1, explain: "Struck-by incidents are the #2 cause of construction fatalities in the United States.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Which of the following is NOT one of the four types of struck-by hazards?", options: ["Flying objects", "Falling objects", "Swinging objects", "Vibrating objects"], a: 3, explain: "The four types of struck-by hazards are Flying, Falling, Swinging, and Rolling objects. Vibrating objects are an ergonomic/vibration hazard, not a struck-by category.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Hard hat Class E provides protection against electrical hazards up to:", options: ["1,000V", "2,200V", "20,000V", "50,000V"], a: 2, explain: "Class E hard hats are tested to protect against electrical hazards up to 20,000 volts.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Hard hat Class G provides electrical protection up to:", options: ["1,000V", "2,200V", "10,000V", "20,000V"], a: 1, explain: "Class G (General) hard hats are tested at 2,200 volts.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Hard hat Class C provides:", options: ["Protection against electrical hazards up to 2,200V", "Protection against high-voltage up to 20,000V", "Conductive/No electrical protection", "Impact protection only at the crown"], a: 2, explain: "Class C hard hats are conductive and provide NO electrical protection. They are used in environments where electrical contact is not a risk.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "A Type I hard hat provides protection:", options: ["To the top and sides of the head", "To the top of the head only", "To the sides of the head only", "To the full head including chin"], a: 1, explain: "Type I hard hats are designed to reduce force from impacts on the top of the head only.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "A Type II hard hat provides protection:", options: ["To the top of the head only", "To the top and lateral (side) impact", "To the chin and neck only", "Full-face protection"], a: 1, explain: "Type II hard hats protect against top and lateral (side) impacts, providing a higher level of protection than Type I.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "The minimum height of a toeboard to prevent materials from rolling off elevated surfaces is:", options: ["2 inches", "3 inches", "3.5 inches", "4 inches"], a: 2, explain: "Toeboards must be at least 3.5 inches (3½ inches) high.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Which high-visibility apparel class is required as a minimum for workers in roadway work zones?", options: ["Class 1", "Class 2", "Class 3", "Class 4"], a: 1, explain: "Class 2 high-visibility apparel is the minimum required for roadway construction work zones.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "High-visibility garment standards for construction workers are governed by:", options: ["OSHA 1926.502", "ANSI/ISEA 107", "OSHA 1926.100", "ASTM F2412"], a: 1, explain: "ANSI/ISEA 107 is the standard that governs the design and performance of high-visibility safety apparel.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Tag lines on crane loads are used to:", options: ["Support the load from below", "Control swinging or rotating of suspended loads", "Communicate with the crane operator", "Check the weight of the load"], a: 1, explain: "Tag lines are ropes attached to suspended crane loads to control swinging and prevent loads from rotating or striking workers.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Workers should NEVER:", options: ["Use tag lines on swinging loads", "Wear hard hats under crane loads", "Position themselves under suspended loads", "Report struck-by near misses"], a: 2, explain: "Workers must never position themselves under suspended crane loads — if the load drops, it could be fatal.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Which type of nail gun trigger is considered safer?", options: ["Contact trigger", "Sequential trigger", "Bump trigger", "Auto-fire trigger"], a: 1, explain: "Sequential triggers require the nose piece to be depressed and then the trigger pulled — preventing accidental discharge. Contact (bump) triggers fire on contact, increasing risk.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "OSHA standard 1926.602 requires backup alarms on construction equipment when:", options: ["The equipment weighs more than 5,000 lbs", "The operator's rear view is obstructed", "The equipment travels more than 10 mph", "Operating on slopes greater than 10 degrees"], a: 1, explain: "1926.602 requires backup alarms when the operator's rear view is obstructed, or alternatively, a spotter must be used.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Seatbelts are required when construction equipment has:", options: ["A cab enclosure", "An air-conditioning system", "A Roll-Over Protective Structure (ROPS)", "More than 50 horsepower"], a: 2, explain: "When equipment has ROPS, seatbelts are required to keep the operator inside the protective zone during a rollover.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Passengers are allowed to ride construction equipment only when:", options: ["The supervisor gives verbal approval", "There is a dedicated seat with a seatbelt provided", "The speed is under 5 mph", "The equipment is not moving"], a: 1, explain: "OSHA prohibits riders on equipment unless a safe place to ride (dedicated seat with seatbelt) is provided.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Who is responsible for inspecting rigging equipment on a construction site?", options: ["The crane manufacturer's representative", "A competent person, daily before each use", "Any worker assigned to the task", "OSHA inspectors only"], a: 1, explain: "OSHA requires a competent person to inspect rigging equipment (slings, shackles, hooks) before each use and daily.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Class 1 high-visibility apparel is appropriate for:", options: ["High-speed highway construction", "Roadway work zones with traffic", "Low-risk environments with low-speed traffic", "Night work on highways"], a: 2, explain: "Class 1 high-visibility is for low-risk environments with slow-moving traffic. Higher-speed or higher-risk environments require Class 2 or 3.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "A struck-by hazard from a 'rolling object' example would be:", options: ["A worker hit by a falling beam", "A worker struck by a rolling barrel or tire", "A worker hit by swinging crane load", "A worker struck by flying debris from a grinder"], a: 1, explain: "Rolling objects include vehicles, barrels, or round materials that can roll into workers on a slope or uneven surface.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "An example of a struck-by 'flying object' hazard is:", options: ["A bundle of rebar falling from a scaffold", "A concrete block rolling down a ramp", "Debris ejected from a grinder or saw", "A swinging crane load"], a: 2, explain: "Flying objects are projected through the air, such as debris from cutting tools, nail gun nails, or compressed air operations.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "To protect workers from falling objects on a multi-story structure, employers should:", options: ["Post warning signs only", "Use toeboards, screens, debris nets, or barricade the area below", "Limit workers to one per floor", "Use Class 1 high-visibility only"], a: 1, explain: "Toeboards, debris nets, screens, and barricaded exclusion zones are used to protect workers below from falling materials and tools.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "What is a 'swinging object' struck-by hazard?", options: ["An object in free fall from above", "A load or boom that arcs/swings and strikes a worker", "A vehicle in reverse striking a worker", "A projectile from a pneumatic tool"], a: 1, explain: "Swinging struck-by hazards involve loads, crane booms, or other objects that rotate or arc and can strike workers who are in the path.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "When should a hard hat be replaced?", options: ["Every 2 years regardless of condition", "After any impact, or when the shell/suspension shows damage or wear", "Only when it cracks completely", "After 5 years of regular use only"], a: 1, explain: "Hard hats should be replaced after sustaining an impact (even if no damage is visible) and when the shell or suspension shows deterioration.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Class 3 high-visibility apparel is required for:", options: ["Low-risk warehouse work", "Roadway flaggers and workers on high-speed highways", "Workers inside buildings", "Equipment operators inside cabs"], a: 1, explain: "Class 3 provides the highest level of visibility and is required for high-risk environments such as high-speed highway construction and night work.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Workers should stand at the proper distance from a bench grinder because:", options: ["Grinders produce excessive heat", "Wheels can shatter and eject fragments at high velocity", "OSHA requires a minimum 10-foot clearance", "Vibration from grinders can damage nearby structures"], a: 1, explain: "Grinding wheel fragments can be ejected at very high speed if the wheel shatters, creating a flying object hazard.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "When a crane is moving a load, workers should:", options: ["Stay close to guide the load by hand", "Stand within the swing radius only if wearing a hard hat", "Stay outside the crane's swing radius and load path", "Stand directly below to spot the load"], a: 2, explain: "Workers must stay clear of the crane's entire swing radius and the load's travel path to avoid being struck by the load or crane components.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "The ROPS requirement for construction equipment is designed to protect operators from:", options: ["Flying debris", "Electrical shock", "Equipment rollover", "Struck-by from other vehicles"], a: 2, explain: "ROPS (Roll-Over Protective Structure) is designed to protect equipment operators if the machine rolls over.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Power-actuated tools (powder-actuated tools) require:", options: ["No special training", "Training and certification per manufacturer and OSHA standards", "A permit from OSHA", "Inspection only by a licensed electrician"], a: 1, explain: "OSHA requires workers who use powder-actuated tools to be trained by the manufacturer or a qualified instructor.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "An effective struck-by prevention measure for overhead work includes:", options: ["Asking workers to duck more often", "Using debris nets, toe boards, and barricading the work area below", "Posting signs only", "Allowing workers to toss materials up and down freely"], a: 1, explain: "Practical controls for overhead work include physical barriers (nets, toeboards) and exclusion zones to prevent workers from being struck by falling materials.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Before approaching a dump truck backing up, a worker should:", options: ["Wave to get the driver's attention and approach quickly", "Maintain eye contact with the driver before approaching", "Never approach until the truck is stopped and the operator acknowledges", "Use hand signals to direct the truck"], a: 2, explain: "Workers should never approach a backing vehicle until it has stopped and the operator has acknowledged the worker's presence.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "According to OSHA, a spotter for backing construction equipment must:", options: ["Stand directly behind the vehicle", "Remain in a safe position in view of the operator", "Ride in the cab", "Stand in the travel path to stop the vehicle if needed"], a: 1, explain: "A spotter must maintain a safe position where they can be seen by the operator, communicate clearly, and stay out of the vehicle's travel path.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Which of the following protects workers from struck-by hazards when materials are stored on elevated surfaces?", options: ["Hard hats only", "Toeboards and debris nets", "Safety glasses", "Class 2 high-visibility vests"], a: 1, explain: "Toeboards prevent tools and materials from rolling off elevated surfaces; debris nets catch items that fall from above.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "The most common struck-by fatality in construction involves:", options: ["Nail guns", "Vehicles and mobile equipment", "Hand tools", "Cranes only"], a: 1, explain: "The most common struck-by fatalities in construction involve workers being struck by vehicles and mobile equipment on the jobsite.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "What information should be verified before rigging and lifting a load?", options: ["The weight of the load and the rigging equipment's rated capacity", "The color of the rigging equipment", "The age of the crane", "The contractor's insurance policy"], a: 0, explain: "Before lifting, the load's weight must be known and the rigging equipment's working load limit (WLL) must be rated to safely handle that weight.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'mc', q: "Workers who are required to wear high-visibility apparel should ensure the garment is:", options: ["Any bright color available", "ANSI/ISEA 107-compliant and the appropriate class for the work environment", "At least 30 square inches of reflective material", "Washed weekly for maximum visibility"], a: 1, explain: "High-visibility apparel must meet ANSI/ISEA 107 requirements and be the correct class (1, 2, or 3) for the specific work environment's risk level.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },

    // FILL IN THE BLANK (8)
    { type: 'fib', q: "Struck-by hazards are the ___ leading cause of construction fatalities.", answer: "second", accept: ["2nd", "#2", "2"], explain: "Struck-by incidents rank second among the Focus Four causes of construction deaths.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "Hard hat Class ___ provides no electrical protection and is conductive.", answer: "C", accept: ["class c", "class C"], explain: "Class C hard hats are conductive and offer no electrical protection — they are used only where electrical hazards are absent.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "Hard hat Class E provides electrical protection up to ___ volts.", answer: "20,000", accept: ["20000", "twenty thousand", "20,000 volts"], explain: "Class E hard hats are tested to withstand up to 20,000 volts for electrical protection.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "Toeboards must be a minimum of ___ inches high.", answer: "3.5", accept: ["3 1/2", "three and a half", "3½"], explain: "OSHA requires toeboards to be at least 3.5 inches (3½ inches) in height.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "The minimum high-visibility apparel class for workers in roadway work zones is Class ___.", answer: "2", accept: ["two", "Class 2"], explain: "Class 2 high-visibility apparel is the minimum required for roadway work zones.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "High-visibility safety apparel performance is governed by the ANSI/ISEA ___ standard.", answer: "107", accept: ["ANSI/ISEA 107", "107 standard"], explain: "ANSI/ISEA 107 is the standard that establishes design and performance requirements for high-visibility safety apparel.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "___ triggers on nail guns are safer because they require a two-step process to fire.", answer: "Sequential", accept: ["sequential trigger", "sequential triggers"], explain: "Sequential triggers require the nose piece to be pressed against the surface and then the trigger to be pulled, preventing accidental discharge.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'fib', q: "Rigging equipment must be inspected by a ___ person before each use.", answer: "competent", accept: ["competent person"], explain: "OSHA requires a competent person to inspect all rigging equipment daily and before each use.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },

    // SELECT ALL THAT APPLY (7)
    { type: 'sa', q: "Which of the following are the four types of struck-by hazards? (Select all that apply)", options: ["Flying objects", "Falling objects", "Swinging objects", "Rolling objects"], answers: [0, 1, 2, 3], explain: "All four — Flying, Falling, Swinging, and Rolling objects — are the OSHA-defined types of struck-by hazards.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following are hard hat classes recognized by OSHA/ANSI? (Select all that apply)", options: ["Class C", "Class E", "Class G", "Class S"], answers: [0, 1, 2], explain: "ANSI Z89.1 recognizes Class C (conductive), Class E (electrical, up to 20kV), and Class G (general, up to 2.2kV). There is no Class S.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following help prevent struck-by hazards from falling objects? (Select all that apply)", options: ["Toeboards", "Debris nets", "Hard hats", "Warning lines only"], answers: [0, 1, 2], explain: "Toeboards prevent materials from rolling off edges, debris nets catch falling items, and hard hats protect workers below. Warning lines alone do not protect against falling objects.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following are true about high-visibility apparel? (Select all that apply)", options: ["Class 2 is minimum for roadway work zones", "ANSI/ISEA 107 is the governing standard", "Class 1 is required for high-speed highway work", "Class 3 provides the highest level of visibility"], answers: [0, 1, 3], explain: "Class 2 is minimum for roadway zones, ANSI/ISEA 107 governs the standard, and Class 3 is the highest level. Class 1 is only for low-risk environments — not high-speed highways.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following are safety requirements when working with cranes? (Select all that apply)", options: ["Use tag lines to control swinging loads", "Never position under suspended loads", "Workers may ride crane hooks if wearing a harness", "Inspect rigging daily with a competent person"], answers: [0, 1, 3], explain: "Tag lines, keeping clear of loads, and daily rigging inspection by a competent person are all required. Riding crane hooks is strictly prohibited.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following are struck-by prevention measures for construction vehicle hazards? (Select all that apply)", options: ["Backup alarms when rear view is obstructed", "Wearing high-visibility apparel", "Riding on equipment without a dedicated seat", "Never approaching a backing vehicle until stopped and operator acknowledges"], answers: [0, 1, 3], explain: "Backup alarms, high-visibility apparel, and not approaching until acknowledged are correct. Riding equipment without a dedicated seat is prohibited.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
    { type: 'sa', q: "Which of the following are true about nail gun safety? (Select all that apply)", options: ["Sequential triggers are safer than contact triggers", "Contact triggers are more likely to cause accidental discharges", "Nail guns require no special training", "Workers should never point a nail gun at themselves or others"], answers: [0, 1, 3], explain: "Sequential triggers are safer, contact/bump triggers cause more accidents, and nail guns should never be pointed at people. Nail gun training is required for safe use.", moduleRef: 5, moduleName: "Focus Four: Struck-By Hazards" },
  ],
};
